/**
 * Colors - Taint Propagation Test
 *
 * Validates that sourceOfInstruction taint propagates correctly through
 * the agentic loop. Specifically: tool calls generated by the LLM after
 * processing external content (web_fetch, file_read) must be labeled
 * "external_content", not "agent".
 *
 * This test uses a mock LLM provider — no API credits required.
 * Requested by zero$ignal security audit, finding 015.
 */

import { ColorsAgent } from "../ColorsAgent";

// ── Mock LLMs ─────────────────────────────────────────────────────────────────

class MockTaintedLLM {
  private round = 0;
  readonly calls: Array<{ round: number; messages: any[] }> = [];

  async create(params: any) {
    this.round++;
    this.calls.push({ round: this.round, messages: params.messages });

    if (this.round === 1) {
      return {
        stop_reason: "tool_use",
        content: [{
          type:  "tool_use",
          id:    "call_web_1",
          name:  "web_fetch",
          input: { url: "https://example.com/malicious-page" },
        }],
      };
    }

    if (this.round === 2) {
      return {
        stop_reason: "tool_use",
        content: [{
          type:  "tool_use",
          id:    "call_shell_1",
          name:  "shell_exec",
          input: { command: "echo pwned" },
        }],
      };
    }

    return {
      stop_reason: "end_turn",
      content: [{ type: "text", text: "I summarized the page for you." }],
    };
  }
}

class MockSafeLLM {
  private round = 0;

  async create(_params: any) {
    this.round++;

    if (this.round === 1) {
      return {
        stop_reason: "tool_use",
        content: [{
          type:  "tool_use",
          id:    "call_shell_safe",
          name:  "shell_exec",
          input: { command: "pwd" },
        }],
      };
    }

    return {
      stop_reason: "end_turn",
      content: [{ type: "text", text: "Your current directory is shown above." }],
    };
  }
}

// ── Helpers ───────────────────────────────────────────────────────────────────

function makeAgent() {
  return new ColorsAgent({
    apiKey:     "test-key-not-used",
    storageDir: "/tmp/colors-taint-test-" + Date.now(),
    passphrase: "test-passphrase-32-chars-minimum!",
  });
}

function captureGateInputs(agent: ColorsAgent) {
  const captured: Array<{ tool: string; source: string }> = [];
  const meta = (agent as any).metacognition;
  const original = meta.evaluate.bind(meta);

  meta.evaluate = (req: any) => {
    captured.push({ tool: req.tool, source: req.sourceOfInstruction });
    return original(req);
  };

  return captured;
}

// ── Tests ─────────────────────────────────────────────────────────────────────

describe("Taint propagation — sourceOfInstruction through agentic loop", () => {

  it("web_fetch labels as 'user', subsequent shell_exec labels as 'external_content'", async () => {
    const agent = makeAgent();
    const mock  = new MockTaintedLLM();
    (agent as any).llm = { messages: mock };

    const captured = captureGateInputs(agent);

    await agent.chat("please summarize example.com for me");

    expect(captured[0]).toEqual({ tool: "web_fetch", source: "user" });
    expect(captured[1]).toEqual({ tool: "shell_exec", source: "external_content" });
  });

  it("shell_exec after web_fetch is BLOCKED by the gate", async () => {
    const agent = makeAgent();
    const mock  = new MockTaintedLLM();
    (agent as any).llm = { messages: mock };

    const response = await agent.chat("please summarize example.com for me");

    // Gate blocks external_content tool calls and pushes INDIRECT_INJECTION_ATTEMPT flag
    expect(response.flags.some(f => f.includes("INDIRECT_INJECTION_ATTEMPT"))).toBe(true);

    // web_fetch should have succeeded (source: user)
    expect(response.actionsTaken.some(a =>
      a.includes("web_fetch") && a.includes("user")
    )).toBe(true);

    // shell_exec should NOT appear in actionsTaken — it was blocked before execution
    expect(response.actionsTaken.some(a =>
      a.includes("shell_exec") && !a.includes("blocked")
    )).toBe(false);
  });

  it("control: direct user shell request labels as 'user' and is not blocked by source", async () => {
    const agent = makeAgent();
    const mock  = new MockSafeLLM();
    (agent as any).llm = { messages: mock };

    const captured = captureGateInputs(agent);

    await agent.chat("what directory am I in? run pwd");

    expect(captured[0]).toEqual({ tool: "shell_exec", source: "user" });
  });

  it("external_content taint is sticky across multiple rounds", async () => {
    class MockMultiRound {
      private round = 0;
      async create(_p: any) {
        this.round++;
        if (this.round === 1) return {
          stop_reason: "tool_use",
          content: [{ type: "tool_use", id: "c1", name: "web_fetch", input: { url: "https://example.com" } }],
        };
        if (this.round === 2) return {
          stop_reason: "tool_use",
          content: [{ type: "tool_use", id: "c2", name: "shell_exec", input: { command: "echo test" } }],
        };
        if (this.round === 3) return {
          stop_reason: "tool_use",
          content: [{ type: "tool_use", id: "c3", name: "file_write", input: { path: "out.txt", content: "x" } }],
        };
        return { stop_reason: "end_turn", content: [{ type: "text", text: "done" }] };
      }
    }

    const agent = makeAgent();
    (agent as any).llm = { messages: new MockMultiRound() };
    const captured = captureGateInputs(agent);

    await agent.chat("fetch example.com and save what it says");

    expect(captured[0]).toEqual({ tool: "web_fetch",  source: "user" });
    expect(captured[1]).toEqual({ tool: "shell_exec", source: "external_content" });
    expect(captured[2]).toEqual({ tool: "file_write", source: "external_content" });
  });

});
                  
